function candidate(mapping, segment) {
  var target = this && (this.node || this.output || this.current || this);
  var base = this && (this.baseReference || this.base || this.relativePath || this.sourceRoot);

  if (!mapping || mapping.source == null) {
    return target.add(segment);
  }

  var source = mapping.source;
  if (base) {
    if (typeof require === "function") {
      try {
        var path = require("path");
        source = path.posix ? path.posix.join(base, source) : path.join(base, source);
      } catch (e) {
        source = String(base).replace(/\/$/, "") + "/" + String(source).replace(/^\//, "");
      }
    } else {
      source = String(base).replace(/\/$/, "") + "/" + String(source).replace(/^\//, "");
    }
  }

  if (typeof SourceNode !== "undefined") {
    return target.add(new SourceNode(
      mapping.originalLine,
      mapping.originalColumn,
      source,
      segment,
      mapping.name
    ));
  }

  return target.add({
    line: mapping.originalLine,
    column: mapping.originalColumn,
    source: source,
    name: mapping.name,
    content: segment
  });
}
